"""
MKT Context Commentary — Romans chapters 11–14
Historical, cultural, and background commentary for each verse.
Run: python3 scripts/zc-context-romans-11-14.py
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ROMANS = {
  "11": {
    "1": '<p>Paul identifies himself as an "Israelite, from the seed of Abraham, of the tribe of Benjamin" — the same identification he gives in Philippians 3:5. Benjamin was one of the two southern tribes that remained loyal to the Davidic house after the division of the kingdom; it was the tribe of Israel\'s first king (Saul) and was considered particularly faithful. Paul\'s own conversion as a former persecutor who became an apostle is presented as the supreme evidence that God has not rejected Israel: if Paul himself is a believing Israelite, the principle of the preserved remnant is validated in his person.</p>',
    "2": '<p>The Elijah narrative of 1 Kings 19 was central to Jewish self-understanding of the remnant concept. Elijah, believing himself to be the only faithful Israelite left, flees to Horeb and complains to God that "the Israelites have forsaken your covenant, torn down your altars, and put your prophets to death with the sword. I am the only one left, and now they are trying to kill me too" (1 Kgs 19:10). God\'s response — the revelation of the 7,000 — shows that the remnant was preserved in secret, unknown even to the prophet. Paul uses this as the pattern for his own time: the faithful remnant exists even when it is invisible.</p>',
    "3": '<p>The text Paul cites from Elijah\'s complaint (1 Kgs 19:10, 14) comes from one of the darkest moments in the prophetic tradition. After the great victory over the prophets of Baal at Carmel (1 Kgs 18), Elijah expected national revival; instead he found himself hunted by Jezebel and alone. The pattern — prophetic expectation followed by apparent rejection — maps onto Paul\'s experience: the coming of the Messiah should have brought Israel\'s revival, but instead the majority rejected him. Paul finds in Elijah\'s complaint a biblical precedent for his own lament, and in God\'s answer a biblical promise of the hidden remnant.</p>',
    "4": '<p>The 7,000 who had not bowed the knee to Baal (1 Kgs 19:18) were preserved throughout the Baal apostasy of the northern kingdom under Ahab and Jezebel without Elijah or anyone else knowing of their existence. This hiddenness of the faithful remnant is Paul\'s point: the faithfulness of the elect cannot be measured by visible external circumstances. In Paul\'s day, the believing Jewish remnant (including Paul himself and other Jewish apostles and leaders) represents the 7,000 — the preserved faithful whose existence proves the principle that God has not abandoned his covenant people.</p>',
    "5": '<p>The "election of grace" (<em>kat\' eklogēn charitos</em>) that defines the remnant reflects the election theology Paul developed in ch9 (Jacob over Esau before birth; God\'s purpose according to election standing apart from works). The remnant is not constituted by its own faithfulness but by divine grace choosing within the people. This is consistent with OT remnant theology: in Isaiah, the remnant is what God leaves (<em>she\'ar</em> = what remains after cutting); it is the product of divine preservation, not human heroism.</p>',
    "6": '<p>The grace/works antithesis in the context of the remnant\'s constitution reinforces the argument of chs4-5: if the remnant were defined by works-faithfulness, grace would be meaningless; but if defined by grace, works are not the operative criterion. The Jewish tradition of the "meritorious remnant" — those preserved because of their righteousness — is precisely what Paul is pushing back against. The preservation of the remnant is a grace-act, not a reward-act, which keeps the remnant from being a source of boasting.</p>',
    "7": '<p>The "rest" (<em>hoi loipoi</em>) who were hardened represent the majority of Israel who did not believe. Paul uses three OT texts in vv8-10 to establish scriptural precedent for this judicial hardening: Deut 29:4 (a "spirit of stupor"), Isa 29:10 (the same), and Ps 69:22-23 (a table becoming a snare). This threefold witness — from the Law, the Prophets (Isaiah), and the Writings (Psalms) — follows the Jewish pattern of proof-by-Torah-Nevi\'im-Ketuvim, the three divisions of the Hebrew Bible.</p>',
    "8": '<p>Deuteronomy 29:4 comes from Moses\'s farewell discourse, where he tells Israel that despite seeing the plagues and miracles of the Exodus, God had not yet given them "a heart to understand, eyes to see, or ears to hear" — indicating that spiritual perception is itself a divine gift, not a natural human capacity. Isaiah 29:10 adds the prophet\'s warning that God has poured a spirit of deep sleep on the people\'s leaders, closing their eyes. Paul reads these texts as establishing a pattern of divine withdrawal of spiritual perception from the disobedient, which has reached its culmination in Israel\'s rejection of the Messiah.</p>',
    "9": '<p>Psalm 69 is one of the most frequently cited psalms in the NT, used as a template for understanding Christ\'s suffering (Ps 69:9 in John 2:17; Rom 15:3; Ps 69:21 in John 19:28-30). Paul\'s citation of Ps 69:22-23 is particularly striking because Psalm 69 is a psalm of the suffering righteous: the psalmist prays for God to judge his enemies. Paul applies the imprecatory section to Israel, which means he is reading the psalm as applying to those who reject the Messiah — the ones who gave the righteous sufferer vinegar to drink (Ps 69:21).</p>',
    "10": '<p>The curse of blinded eyes and bent back in Ps 69:23 represents the most extreme form of divine judicial punishment: the disabling of the very faculties (sight, strength) needed to perceive and respond to God. In the OT context of the Psalm, this is a prayer against the psalmist\'s enemies; in Paul\'s application to Israel, it is the description of the current spiritual condition of those who have rejected Christ — not a permanent state but a temporary judicial hardening with an eventual reversal (vv11ff).</p>',
    "11": '<p>The question "did they stumble so as to fall?" introduces the crucial distinction between stumbling (<em>ptaiō</em>) and falling-beyond-recovery (<em>piptō</em>). In Greek usage, <em>piptō</em> can indicate a permanent fall that is unrecoverable (cf. the fall of Adam, the fall of Babylon). Paul\'s answer (<em>mē genoito</em> — certainly not!) insists that Israel\'s stumbling is not the final word. The provocation-to-jealousy logic (from Deut 32:21, already cited in 10:19) is the mechanism: the Gentile mission is designed partly to provoke Israel to recognize what they have passed by.</p>',
    "12": '<p>The "failure" (<em>hēttēma</em>) and "fullness" (<em>plērōma</em>) of Israel form a contrast: if Israel\'s partial failure has brought such riches to the world (the Gentile mission), how much more will Israel\'s fullness bring? The logic mirrors the a-fortiori of ch5 (if reconciliation happened while we were enemies, how much more will salvation be certain now that we are reconciled). The "riches for the nations" language echoes the Abrahamic promise that all nations would be blessed through Abraham\'s seed (Gen 12:3; 22:18).</p>',
    "13": '<p>Paul describes himself as "apostle to the Gentiles" (<em>ethnōn apostolos</em>) — the specific vocation he received at his Damascus road encounter and confirmed at the Jerusalem meeting with the pillar apostles (Gal 2:7-9). His mission to the Gentiles is not indifferent to Israel; rather, Paul understands the Gentile mission as serving Israel\'s ultimate redemption through the jealousy-provocation of Deut 32:21. The Roman letter itself is part of this missionary strategy: establishing a base in Rome for the westward mission to Spain (15:24, 28) while also maintaining the link to Jerusalem and the Jewish mission.</p>',
    "14": '<p>"My own people" (<em>mou tēn sarka</em> = literally "my flesh") — Paul\'s ethnic solidarity with Israel is explicitly invoked. The phrasing echoes 9:3 where Paul used the same "my kin according to the flesh" language in the context of his willingness to be accursed for Israel\'s sake. Paul\'s Gentile mission serves Israel not by abandoning them but by creating the conditions for their jealousy-awakening through the Gentiles\' remarkable reception of the Messiah who was Israel\'s.</p>',
    "15": '<p>The phrase "life from the dead" (<em>zōē ek nekrōn</em>) in v15 describes what Israel\'s full inclusion will bring: something like a general resurrection-event. Jewish eschatology associated the resurrection of the dead with the final age (Dan 12:2; Isa 26:19; Ezek 37). Paul\'s implication is that Israel\'s acceptance (the "fullness" of v12) will coincide with or precipitate the eschatological resurrection. This connects Israel\'s restoration to the final consummation of all things — making Jewish mission ultimately eschatological in its stakes.</p>',
    "16": '<p>The firstfruit and lump image draws on Numbers 15:18-21, which commanded Israel to offer the first portion of their ground grain as an offering to God — an act that consecrated the entire batch. If the first portion is holy, the entire lump shares that holiness. Paul applies this to the patriarchs as the "firstfruits" of Israel: if Abraham, Isaac, and Jacob are holy (consecrated, set apart for God), the entire nation that flows from them participates in that consecration. The root-and-branches metaphor that follows works the same way from the bottom up instead of top down.</p>',
    "17": '<p>The olive tree was one of the most economically significant plants in the Mediterranean world. Olive oil was essential for food, lighting, religious offerings, and medicine; olive groves were valuable long-term investments that took decades to mature and produce abundantly. The image of "the rich root of the olive tree" would have evoked wealth, blessing, and deep rootedness in the Mediterranean audience. Grafting in olive cultivation was practiced to improve yield on weak trees; the Roman agricultural writer Columella (De Re Rustica 5.9) describes olive grafting in detail.</p>',
    "18": '<p>The warning to the Gentile branches "do not boast over the branches" (<em>mē katakauchō tōn kladōn</em>) addresses a specific danger in the mixed Roman church. If Jewish Christians were a minority in Rome (following the expulsion under Claudius and partial return), Gentile Christians might be tempted toward supersessionism — the view that the church had simply replaced Israel without remainder. Paul\'s agricultural metaphor insists on continuity: the Gentile branches are grafted into an existing, living tree with deep roots, not planted in new soil.</p>',
    "19": '<p>The Gentile objector who says "Branches were broken off so that I could be grafted in" reflects a real theological position that Paul counters. The objection assumes that Israel\'s partial failure was designed for Gentile benefit as its sole purpose — making Israel\'s role merely instrumental. Paul\'s response (v20-21) affirms that unbelief was the reason for the breaking but warns that the same condition (faith) is required to remain grafted in. The branches were not broken for you but because of their unbelief; you are not there by right but by faith.</p>',
    "20": '<p>The contrast "they were broken off because of unbelief and you stand because of faith" establishes the identical criterion for both Jewish and Gentile relationship to the olive tree covenant: faith, not ethnicity. The corollary warning — "do not be proud but be afraid" (<em>mē hypsēlophronei alla phobou</em>) — reflects the Roman cultural tendency to pride in status and achievement. The Gentile Christians who might feel secure in their superior-seeming position (not having rejected the Messiah) are warned by the example of Israel that the condition of remaining grafted in is ongoing faith, not past reception.</p>',
    "21": '<p>The argument from the greater to the lesser: if God did not spare the natural branches (Israel), he will certainly not spare the grafted Gentile branches who become arrogant. The "natural" olive tree branches represent Israel\'s prior covenantal standing — their rootedness in the patriarchal promises and the Mosaic covenant. If those advantages did not protect the unbelieving Israelites from being cut off, the Gentile branches have even less basis for security based on their position alone.</p>',
    "22": '<p>The juxtaposition of God\'s "kindness and sternness" (<em>chrēstotēs kai apotomia</em>) — the same vocabulary Paul used in 2:4 (God\'s kindness intended to lead to repentance) — presents the two faces of the divine character that Israel\'s story illustrates. The agricultural metaphor makes the point concretely: branches are kept in the tree by continued bearing of fruit (faith producing life); unfruitful branches are cut off regardless of their prior position in the tree. The Pauline warning is not hypothetical for Rome: the history of the church shows communities that flourished and then died.</p>',
    "23": '<p>The possibility of natural branches being "grafted back in" (<em>enkentristhēsontai</em>) if they do not persist in unbelief maintains the eschatological hope for Israel. Paul\'s future tense ("they will be grafted in") is not merely conditional but carries a promise-flavor: the same God who can graft Gentiles into the olive tree is "able" (<em>dynatos</em>) — a word that in Paul often signals divine power doing what nature cannot (cf. 4:21 on Abraham\'s faith in the divine ability to do what he promised).</p>',
    "24": '<p>The argument from the less-natural to the more-natural: it is "against nature" (<em>para physin</em>) to graft a wild olive branch into a cultivated tree (Roman agricultural practice normally went the other direction — grafting cultivated branches into wild stock to strengthen production). If God can accomplish the less-natural thing (Gentile inclusion), how much more the more-natural thing (Israel\'s restoration to its own covenantal tree). The agricultural metaphor\'s logic of "much more certainly" mirrors the a-fortiori arguments of ch5.</p>',
    "25": '<p>The "mystery" (<em>mysterion</em>) disclosure in v25 is one of Paul\'s several uses of this term for previously hidden divine purposes now revealed (cf. 1 Cor 15:51; Col 1:26-27; Eph 3:3-6). In Jewish apocalyptic, "mystery" (<em>raz</em> in Aramaic, used in Daniel and extensively in the Qumran texts) referred to the hidden plan of God revealed to the prophet for the end times. The specific mystery here — Israel\'s hardening is partial and temporary ("until the fullness of the Gentiles comes in") — gives a temporal structure to the divine plan that would prevent Gentile triumphalism by insisting the story is not yet over for Israel.</p>',
    "26": '<p>"All Israel will be saved" (<em>pas Israēl sōthēsetai</em>) is among the most debated statements in Paul. The interpretive options include: (a) the full number of elect ethnic Jews across history; (b) the entire nation of ethnic Jews at the eschatological end; (c) the complete Israel = the church (Gentiles + Jews); (d) "all kinds of Israel" = a representative Israel. The context strongly favors an ethnic referent since Paul has been discussing Jewish unbelief and hardening specifically, and the citation that follows (Isa 59:20-21) describes the deliverer coming to Zion to remove Jacob\'s sins — clearly ethnic Israel in Isaiah\'s context.</p>',
    "27": '<p>The citation of Isaiah 59:20-21 is combined with elements of Jeremiah 31:33-34 (the new covenant promise of forgiveness of sins). Isaiah 59:20 in the Hebrew reads "the Redeemer will come to Zion"; Paul (with LXX variant) reads "from Zion," changing the directional preposition in a way that makes the deliverer\'s coming from Zion (from the heavenly Jerusalem, from Christ\'s resurrection and exaltation) rather than toward the earthly city. This Christological re-reading reorients the Isaianic hope around the already-exalted Christ who will return.</p>',
    "28": '<p>The phrase "irrevocable" (<em>ametamelēta</em>) applied to God\'s gifts and calling in v29 is significant in the context of Roman gift-law. A gift formally given under Roman law could be revoked under certain circumstances, but a solemn public gift-promise was considered binding on the giver. Paul\'s <em>ametamelēta</em> (without-regret, without-second-thought) asserts that God\'s covenantal gifts to Israel — the adoption, the glory, the covenants, the law-giving, the worship, and the promises of 9:4-5 — have not been and cannot be recalled, even in the face of Israel\'s present unbelief. The ground is God\'s character, not Israel\'s performance.</p>',
    "29": '<p>The theological principle "the gifts and calling of God are irrevocable" became foundational for subsequent Christian theology of Israel and for various understandings of divine immutability and covenant faithfulness. The Reformation debates about election and perseverance drew heavily on this verse. In Paul\'s immediate context, the principle grounds the eschatological hope for Israel: if God\'s election-calling is irrevocable, Israel\'s current unbelief cannot be the final word; the calling will eventually reach its intended end in Israel\'s salvation.</p>',
    "30": '<p>The parallel structure of vv30-31 works by analogy: just as the Gentiles were disobedient and received mercy through Israel\'s disobedience, so Israel is now disobedient so that it also may receive mercy through the mercy shown to Gentiles. The symmetry is precise and deliberate: both groups begin in disobedience; both receive mercy through the other\'s disobedience. No group has grounds for boasting: both are mercy-recipients, not mercy-deservers. The Gentile church\'s mercy-reception is a link in the chain of Israel\'s eventual mercy-reception.</p>',
    "31": '<p>The future tense "so that they also may now receive mercy" (<em>hina kai autoi nyn eleēthōsin</em>) maintains the temporal urgency of the Jewish mission in Paul\'s present. The "now" (<em>nyn</em>) signals that Israel\'s mercy-reception is not merely a distant eschatological event but something that the present gospel proclamation aims to bring about. This connects the doxological conclusion of ch11 back to the practical evangelistic urgency that Paul\'s own mission embodies.</p>',
    "32": '<p>"God has bound all under disobedience in order to have mercy on all" (<em>synekleisen gar ho theos tous pantas eis apeitheian hina tous pantas eleēsē</em>) is Paul\'s theological summary of the entire human narrative: both Israel and Gentiles have been enclosed in disobedience, making mercy the universal divine response to the universal human condition. <em>Synkleiō</em> (to shut together, confine, enclose) is the word used for netting fish (Luke 5:6) and for being "held captive" by the law (Gal 3:22-23). God has orchestrated history so that all human self-sufficiency is collapsed, making mercy the only possible mode of divine-human relationship.</p>',
    "33": '<p>The doxology of vv33-36 is one of the most sustained doxological passages in Paul and draws on both the form and content of Jewish doxological prayers. The <em>Berakah</em> (blessing formula) tradition of Jewish prayer expressed wonder at God\'s actions through praise; Paul\'s doxology converts the theological argument of chs9-11 into worship. The threefold "O depth" (<em>bathos</em>) of riches, wisdom, and knowledge (<em>ploutou kai sophias kai gnōseōs</em>) echoes the prophetic tradition of divine incomprehensibility (Isa 40:13-14; Ps 139; Job 38-41).</p>',
    "34": '<p>The citation of Isaiah 40:13 LXX ("who has known the mind of the Lord?") comes from the great consolation section of Deutero-Isaiah that opens with "Comfort, comfort my people" and assures the exiles that the incomprehensible God who measured the waters in the hollow of his hand is also the God who leads his people home. The rhetorical question establishes divine cognitive transcendence: no human or angelic counselor has advised God or contributed to his plan. The wisdom of the divine plan for Jews and Gentiles disclosed in chs9-11 is a window into an inexhaustible divine mind.</p>',
    "35": '<p>The citation of Job 41:11 (LXX) — "who has given to God first, that God should repay them?" — comes from the climax of God\'s speeches to Job from the whirlwind, where God asserts his absolute sovereignty over creation. The point is the impossibility of prior-gift to God: no one has ever placed God in their debt. This principle eliminates any claim to divine obligation: God owes nothing to any creature, making all divine giving — including salvation — purely gracious rather than responsive to prior human merit or service.</p>',
    "36": '<p>The closing formula "from him and through him and to him are all things" (<em>ex autou kai di\' autou kai eis auton ta panta</em>) reflects the Stoic cosmological formula that described the <em>logos</em> as the source, sustainer, and goal of all reality. Stoic writers (Marcus Aurelius, Epictetus) used similar threefold formulas for the divine principle. Paul takes this cosmological formula and applies it to the God of Israel who has been revealed in the gospel: the same God who is the source and goal of all things has made his purposes known through the Christ-event. "To him be the glory forever, amen" is the Jewish doxological conclusion that transforms the Stoic formula into worship.</p>'
  },
  "12": {
    "1": '<p>The appeal to "present your bodies as a living sacrifice" (<em>parastēsai ta sōmata hymōn thysian zōsan</em>) draws on the entire Levitical sacrificial system while inverting its fundamental logic. The OT system required the death of the animal for it to become an offering; Paul\'s "living sacrifice" (<em>thysian zōsan</em>) is a sacrifice that lives in the act of offering. This is the eschatological transformation of worship: the temple of the new covenant is the community of believers, and the sacrifice is not dead animals but living persons. The phrase "reasonable worship" (<em>logikēn latreian</em>) uses the Stoic term <em>logikos</em> (rational, consistent with the logos) to describe the worship that befits rational beings: not external ritual but the reasonable ordering of the entire self toward God.</p>',
    "2": '<p>The "present age" (<em>aiōn houtos</em>) and "transformation" (<em>metamorphousthe</em>) draw on Jewish apocalyptic\'s two-age structure (this age/the age to come) and on Hellenistic metamorphosis language. The "conforming" (<em>syschēmatizesthe</em>) to the present age describes the external pressure of cultural conformity — like pressing clay into a mold — while the "transforming" (<em>metamorphousthe</em>) by the renewal of the mind describes the interior divine operation that changes the shape of the person from within. The contrast is between external conformity to a transient age and interior transformation oriented toward the permanent new age.</p>',
    "3": '<p>Paul\'s call for "sober thinking" (<em>sōphronein</em>) about one\'s measure of faith echoes the Greek virtue of <em>sōphrosynē</em> (prudence, self-control, moderation — one of the four cardinal virtues). In the context of a community that had experienced dramatic spiritual manifestations (speaking in tongues, prophecy, healings), the temptation toward spiritual pride and inflated self-assessment was real. Paul\'s "measure of faith" (<em>metron pisteōs</em>) given to each person equalizes the community: all have received faith as God\'s gift, but in different measures suited to different functions.</p>',
    "4": '<p>The body-and-members metaphor for the church was common in Greco-Roman political philosophy. The Stoic Menenius Agrippa used a body-members fable to address class conflict in Rome (Livy, Ab Urbe Condita 2.32); the Stoics used the body metaphor for the interconnected nature of the <em>polis</em>. Paul uses the same metaphor but with a different theological grounding: the unity of the body is not natural civic solidarity but union "in Christ" — the church is Christ\'s body because it is in Christ, not because it is naturally unified.</p>',
    "5": '<p>The formula "we, though many, are one body in Christ" (<em>hoi polloi hen sōma esmen en Christō</em>) reflects the early Christian eucharistic theology: 1 Cor 10:17 makes the same connection between the one bread, the many, and the one body. In the Roman church where Jew-Gentile, slave-free, and rich-poor tensions were real, the one-body claim was not merely theological but politically demanding. Sharing table fellowship across these divisions — as the eucharist required — was itself a bodily enactment of the theological claim.</p>',
    "6": '<p>The list of charismata (grace-gifts) in vv6-8 is similar to but not identical with the gift-lists in 1 Cor 12:8-10 and 28-30. Prophecy (<em>prophēteia</em>) heads the list in both Corinthians and Romans, suggesting its priority in early Christian community life. In Jewish tradition, prophecy had been associated with the age of the Spirit; the community that experienced prophecy was living evidence that the new age had arrived. The "proportion of faith" (<em>analogia tēs pisteōs</em>) by which prophecy is exercised suggests a self-regulating principle: the prophet speaks within the bounds of their faith-understanding, not beyond it.</p>',
    "7": '<p>The ministry of "service" (<em>diakonia</em>) in v7 refers to practical acts of care and distribution rather than a formal ecclesiastical office (the deaconate of Acts 6 and 1 Tim 3 may or may not be in view). In the Roman church, where wealthy patrons supported the community materially, the distribution of resources was a significant community function. The "teaching" (<em>didaskalia</em>) would have been the instruction of converts in the content of the faith — the theological formation function that complemented prophecy\'s spontaneous Spirit-speech.</p>',
    "8": '<p>The gifts of "encouraging" (<em>parakalōn</em>), "giving" (<em>metadidous</em>), "leading" (<em>proistamenos</em>), and "showing mercy" (<em>eleōn</em>) describe the community support functions that were essential in the first-century church without state welfare systems. The wealthy patron who gave simply (not for social advantage — <em>en haplotēti</em>, with singleness) and the leader who led with diligence and the mercy-shower who acted with cheerfulness are community roles that reflect the practical social reality of early Christian communities as mutual-aid societies within the Roman patron-client system.</p>',
    "9": '<p>The rapid-fire ethical instructions of vv9-21 follow the tradition of Jewish wisdom literature (Proverbs, Ben Sira, the Testaments of the Twelve Patriarchs) and Hellenistic moral philosophy in presenting clusters of ethical maxims. Paul\'s "love without hypocrisy" (<em>hē agapē anypokritos</em>) targets a specific cultural vice: the performative love that was characteristic of the patron-client system, where generosity was calculated to produce social return. The "sincere love" the gospel demands is structurally incompatible with the Roman system of reciprocal social obligation.</p>',
    "10": '<p>Philadelphia (<em>philadelphia</em> = brotherly love, love for fellow believers) was a term from family relationships extended to the church community. The instruction to "outdo one another in showing honor" (<em>tē timē allēlous proēgoumenoi</em>) — literally "going before one another in honor" — inverts the Roman social competition for honor and status. In Roman culture, seeking to be honored by others was a driving social motivation; Paul\'s community is to compete in honoring others rather than in receiving honor.</p>',
    "11": '<p>The instruction to be "fervent in spirit" (<em>tō pneumati zeontes</em> — literally "boiling in the spirit") draws on the image of heated wine or boiling water for intense enthusiasm. The phrase "serving the Lord" (<em>tō kyriō douleuontes</em>) with a textual variant "serving the time" (<em>tō kairō douleuontes</em>) in some manuscripts — a difference of one Greek letter — reflects early scribal uncertainty but the "serving the Lord" reading is almost certainly correct. The call to serve the Lord with fervent spirit reframes the community\'s activity as worship rather than social service alone.</p>',
    "12": '<p>The triad "rejoicing in hope, patient in tribulation, persistent in prayer" (<em>tē elpidi chairontes, tē thlipsei hypomenontes, tē proseuchē proskarterountes</em>) is a compressed description of the Christian life under pressure. The Psalmic tradition provides the background for this combination: Psalm 27:14, 34:1, and 37 all combine joy, patient waiting, and persistent prayer in the face of opposition. The Roman church, navigating the aftermath of Claudius\'s expulsion and Nero\'s growing hostility, needed precisely this combination of virtues.</p>',
    "13": '<p>Hospitality (<em>philoxenia</em> = love of strangers) was both a Jewish obligation (Lev 19:34; Gen 18-19) and a Greco-Roman virtue, but with different emphases. Jewish hospitality was rooted in the command to love the stranger "as yourself" because Israel was a stranger in Egypt. Greco-Roman hospitality (<em>xenia</em>) was a formal institution of reciprocal obligation between guest-friends. Paul\'s instruction to "practice hospitality" (<em>diōkontes</em> = pursuing, chasing — the same word used for persecution in v14) in the context of the Roman church reflects the practical need: traveling missionaries and displaced believers needed shelter and support in a world without hotels for the non-wealthy.</p>',
    "14": '<p>The instruction to "bless those who persecute you" echoes Jesus tradition preserved in Matthew 5:44 and Luke 6:27-28. Paul\'s version is the closest NT parallel to the Sermon on the Mount\'s love-enemy ethic outside the Gospels, suggesting that this teaching was widely known in early Christian communities. In the Roman social context where retaliation was a legal right and social expectation, the non-retaliation ethic was a radical departure from normal practice. The blessing of persecutors was not passive acquiescence but an active counter-move in the social realm.</p>',
    "15": '<p>The call to "rejoice with those who rejoice and weep with those who weep" is a compressed expression of the emotional solidarity that characterized early Christian community life. In a society structured by honor-competition where another\'s success was often experienced as a zero-sum loss, the call to genuinely share in others\' joy was countercultural. Plutarch criticized those who could not share in friends\' successes (Moralia 91-92); Paul calls for the opposite orientation — genuine empathy in both directions of the emotional spectrum.</p>',
    "16": '<p>"Do not be proud" (<em>mē ta hypsēla phronountes</em> — literally "not setting the mind on high things") returns to the <em>phroneō</em> (mindset) vocabulary of ch8 and the "sober thinking" of 12:3. "Associate with the lowly" (<em>tois tapeinois synapagomenoi</em>) — either "the lowly" as people of low social status or "lowly things" as humble tasks — calls for the reversal of Roman social aspiration. "Do not be wise in your own estimation" (<em>mē ginesthe phronimoi par\' heautois</em>) echoes Prov 3:7 and Isa 5:21, both condemning self-referential wisdom that ignores divine and communal accountability.</p>',
    "17": '<p>The principle "do not repay evil for evil" (<em>mēdeni kakon anti kakou apodidontes</em>) was not unique to Christianity; Seneca (De Beneficiis 4.26.1) and other Stoics advocated non-retaliation for philosophical reasons. Jewish tradition also included non-retaliation commands (Prov 20:22; 24:29; Lev 19:18). But the instruction to "take thought for what is honorable in the sight of all" (<em>pronoountes kala enōpion pantōn anthrōpōn</em>) adds a missionary dimension: the community\'s behavior should be such that even outsiders recognize it as genuinely honorable, removing the basis for accusation against the church.</p>',
    "18": '<p>"If possible, as far as it depends on you, live peaceably with all" (<em>ei dynaton, to ex hymōn, meta pantōn anthrōpōn eirēneuontes</em>) — the two qualifications are significant: "if possible" acknowledges that peace does not always depend on the Christian community alone, and "as far as it depends on you" limits the obligation to what is within the community\'s control. This is a realistic rather than idealistic ethics: the community cannot control others\' hostility, but it can control its own response. The Roman church, living in the volatile social conditions of Nero\'s early reign, needed this realism alongside the imperative of peace-seeking.</p>',
    "19": '<p>"Vengeance is mine, I will repay, says the Lord" (<em>emoi ekdikēsis, egō antapodōsō, legei kyrios</em>) cites Deut 32:35 from the Song of Moses (with LXX and Targum variant rather than the MT "to me belongs vengeance and recompense"). The Song of Moses was a key text in both Jewish and early Christian theology of divine judgment; Paul already cited it in 10:19 for Israel\'s provocation. The point here is not that God will certainly punish the community\'s enemies but that vengeance belongs to God\'s sphere, not the community\'s: by claiming the right of vengeance, the community would be usurping divine prerogative.</p>',
    "20": '<p>The instruction to feed the hungry enemy and give them drink, thereby "heaping coals of fire on their head" (<em>anthrakas pyros sōreuō epi tēn kephalēn autou</em>), cites Proverbs 25:21-22. The "coals of fire" image has generated extensive debate. The Egyptian background involves a ritual of carrying a basin of burning coals on the head as a sign of repentance and public shame; feeding the enemy causes them the shame of recognizing their own enmity against a benefactor. The Hellenistic background understands the coals metaphorically as the burning pain of shame that generosity inflicts on the hostile. Both readings make the enemy the one who is changed by the generous act, not punished by God.</p>',
    "21": '<p>"Do not be overcome by evil but overcome evil with good" — the closing summary of vv9-21 states the positive principle after the negative prohibitions. The military vocabulary of overcoming (<em>nikaō</em>) inverts the expected dynamic: in the world of Roman power, evil was overcome by greater force; Paul\'s community overcomes evil by deploying good. The practical expression of this principle in the Roman context — blessing persecutors, not retaliating, feeding enemies — makes the ethics concrete rather than abstract.</p>'
  },
  "13": {
    "1": '<p>Romans 13:1-7 was written during Nero\'s early reign (54-68 CE), which began as the "golden quinquennium" (first five years) under the benevolent influence of Seneca and Burrus — the period Suetonius describes as marked by clemency and justice. The specific context of the Roman church includes the aftermath of Claudius\'s expulsion of Jews (and presumably Jewish Christians) from Rome in 49 CE (Suetonius, "Claudius" 25.4, referring to disturbances "at the instigation of Chrestus") and their gradual return after Claudius\'s death in 54 CE. The community returning to Rome needed guidance on relating to the governing authorities who had previously expelled them.</p>',
    "2": '<p>Paul\'s instruction that "those who resist the authority have opposed the ordinance of God" (<em>hoi de antitassomenoi tē tou theou diatagē anthestēkasin</em>) reflects the Jewish tradition of viewing human government as part of God\'s providential ordering. Josephus (Antiquities 20.251) and various rabbinic texts affirm that God appoints rulers. The specific danger Paul addresses may be the Jewish-Christian zealotism that was agitating against Roman taxation (a cause of the Jewish revolt of 66-70 CE that Paul may have foreseen). The instruction is pragmatic and pastoral, not a theological absolutization of state authority.</p>',
    "3": '<p>The distinction between "doing good" (<em>agathos</em>) and "doing evil" (<em>kakos</em>) as what determines one\'s relationship to the governing authorities reflects the Hellenistic theory of the good ruler who rewards virtue and punishes vice. Aristotle (Nicomachean Ethics), the Stoics, and Jewish wisdom literature all shared the idea that legitimate government exists to encourage virtue and suppress vice. Paul\'s description of government as God\'s servant for good (<em>diakonos eis to agathon</em>) is the theological version of this political philosophy, grounding the state\'s legitimate function in divine appointment.</p>',
    "4": '<p>The sword (<em>machaira</em>) that the governing authority "bears" represents the Roman <em>ius gladii</em> (right of the sword) — the legal authority of provincial governors to execute capital punishment. Roman magistrates wore the sword as a symbol of their judicial power; provincial governors received it as the emblem of their office. Paul acknowledges this legal-military reality as part of God\'s ordering of the present age. The qualifier "avenger who carries out God\'s wrath on the wrongdoer" (<em>ekdikos eis orgēn tō to kakon prassounti</em>) limits the divine sanction: the sword is divinely sanctioned specifically for punishment of actual wrongdoing, not arbitrary use of force.</p>',
    "5": '<p>The dual motivation for submission — "because of wrath" (<em>dia tēn orgēn</em>) and "for the sake of conscience" (<em>dia tēn syneidēsin</em>) — distinguishes external compulsion from internal moral reason. <em>Syneidēsis</em> (conscience, the faculty of moral self-awareness) appears frequently in Paul (1 Cor 8, 10; 2 Cor 1:12; 4:2; 5:11) as the inward moral monitor. Submission to governing authorities "for conscience\' sake" means that it is genuinely right, not merely prudent, to honor human authority structures that serve their proper God-appointed functions.</p>',
    "6": '<p>Taxes (<em>phorous</em> = the <em>tributum</em>, the provincial poll-tax and property-tax) and revenue (<em>telē</em> = the <em>portorium</em>, customs duties and tolls) were the two main categories of Roman taxation. The tributum was collected from non-Roman citizens in the provinces; the portorium was a transit tax on goods. Jewish communities had debated whether paying tribute to Rome constituted idolatrous submission to a pagan overlord — the background to the "render to Caesar" question posed to Jesus (Mark 12:13-17). Paul grounds tax-payment in the divine appointment of government servants (<em>leitourgoi theou</em> = "servants/liturgists of God" — using the LXX term for temple servants!).</p>',
    "7": '<p>The instruction to "pay to all what is owed" (<em>apodote pasin tas opheilas</em>) — tax to whom tax is owed, revenue to whom revenue, respect to whom respect, honor to whom honor — applies the debt-cancellation logic of 13:8 (owe nothing to anyone except love) to the specific domain of civic obligations. The differentiation of obligations (tax, revenue, respect, honor) reflects Roman social stratification: different obligations were owed to different levels of authority. Paul insists on meeting each obligation appropriately rather than claiming Christian freedom as exemption from civic duty.</p>',
    "8": '<p>The transition from civic obligations (vv1-7) to the love-commandment (vv8-10) is structured around the Greek word <em>opheilo</em> (owe, have a debt). Verses 1-7 describe paying what is owed to governing authorities; v8 pivots: the one debt that never gets paid off is love — "owe nothing to anyone except to love one another." Jewish tradition summarized the Torah in terms of love: Hillel\'s negative golden rule (b. Shabbat 31a: "What is hateful to you, do not do to your neighbor"), and Jesus\'s double command to love God and neighbor (Mark 12:29-31) all stand in this tradition of Torah-summary.</p>',
    "9": '<p>The commandments Paul cites (do not commit adultery, do not murder, do not steal, do not covet — from the Decalogue\'s second table) plus "any other commandment" are summarized in Lev 19:18: "love your neighbor as yourself." The specific selection — omitting "do not bear false witness" and varying the order — may reflect the early Christian catechetical summary of the Decalogue or the LXX manuscript tradition. The use of Lev 19:18 as the summary principle was shared with the Jesus tradition (Matt 22:39; Mark 12:31; Luke 10:27) and with Philo (On the Special Laws 2.63) who also identified love of neighbor as the summary of the second table.</p>',
    "10": '<p>The identification of love as the "fulfillment" (<em>plērōma</em>) of the law connects to the same verb in 8:4 (the righteous requirement of the law is "fulfilled" in those who walk in the Spirit). Love does not abrogate the law\'s specific commands but completes them — the person who genuinely loves their neighbor will not commit adultery, murder, steal, or covet against them. Augustine\'s famous formulation "Love God and do what you will" (<em>Dilige, et quod vis fac</em>) attempts to capture this principle: love as the fulfillment of law means that love is the condition from which all law-keeping naturally flows.</p>',
    "11": '<p>The eschatological urgency of vv11-14 echoes the early Christian expectation of Christ\'s return as imminent. The phrase "salvation is nearer now than when we first believed" (<em>engyteron hēmōn hē sōtēria ē hote episteusamen</em>) uses the nearness of salvation as the motivation for ethical vigilance. In the Roman world, the pre-dawn darkness before sunrise was the time of maximum danger: thieves operated by night (1 Thess 5:7-8; cf. 1 Pet 5:8). The metaphor of waking from sleep and putting on armor exploits this shared cultural experience to convey eschatological readiness.</p>',
    "12": '<p>The "armor of light" (<em>ta hopla tou phōtos</em>) draws on the military equipment familiar to Roman readers — the full kit of the Roman legionary — and applies it metaphorically to the believer\'s moral equipment. Paul uses the armor metaphor more extensively in Ephesians 6:11-17 and 1 Thessalonians 5:8. The image appears in Isa 59:17 (God putting on righteousness as a breastplate and salvation as a helmet), providing the OT background. The "deeds of darkness" (<em>ta erga tou skotous</em>) that are to be cast off are the behaviors characteristic of the "present age" that is passing away.</p>',
    "13": '<p>The list of behaviors to be abandoned — "carousing and drunkenness, sexual immorality and sensuality, strife and jealousy" (<em>kōmois kai methais, koitais kai aselgeiaiis, eridi kai zēlō</em>) — describes the moral landscape of Roman urban life. Banqueting culture (<em>kōmos</em> = revelry after dinner, often extended into the night with wine, entertainment, and sexual license) was a standard feature of upper-class Roman social life. The Roman satirists (Juvenal, Petronius\'s Satyricon) depict the excesses of the Roman dinner party culture from which some converts were presumably emerging.</p>',
    "14": '<p>The instruction to "put on the Lord Jesus Christ" (<em>endysasthe ton kyrion Iēsoun Christon</em>) picks up the baptismal clothing-imagery of Galatians 3:27 ("as many of you as were baptized into Christ have put on Christ"). Baptismal ritual involved removing one\'s clothing before entering the water and being clothed with a new white garment afterward — a liturgical enactment of the "putting off the old" and "putting on the new" that Paul describes. The "provision for the flesh" (<em>pronoian tēs sarkos</em> = "forethought for the flesh") to be avoided refers to the deliberate advance planning of fleshly indulgence — premeditated rather than impulsive sin.</p>'
  },
  "14": {
    "1": '<p>The "one who is weak in faith" (<em>ton de asthenunta tē pistei</em>) in the Roman church context almost certainly refers primarily to Jewish Christians (and possibly some Gentile God-fearers) who maintained Torah dietary scruples and possibly calendar observances even after coming to faith in Christ. The specific issues in chs14-15 — abstaining from meat (v2), observing certain days (v5), abstaining from wine (v21) — correspond to practices that diaspora Jews followed when kosher meat was unavailable or uncertain, and when Jewish festivals were observed. The "strong" (<em>hoi dynatoi</em>, 15:1) are primarily Gentile Christians who do not observe these practices.</p>',
    "2": '<p>Vegetarianism in Rome had multiple possible backgrounds: (a) Jewish dietary practice in the diaspora where kosher meat was unavailable; (b) the concern about meat sold in the Roman markets being offered to idols (cf. 1 Cor 8-10 which addresses the same issue in Corinth); (c) Pythagorean-influenced vegetarianism (the Neopythagorean movement was influential in Rome). The "weak" person who eats only vegetables (<em>lachanon esthiei</em>) has made the safer choice: vegetables were never involved in pagan sacrificial systems, making them unambiguously clean for all parties.</p>',
    "3": '<p>The social dynamic Paul addresses is the mutual contempt between the communities: the strong "despise" (<em>exouthoneitō</em> = look down on, treat as nothing) the weak, and the weak "judge" (<em>krinetō</em> = condemn, pass judgment on) the strong. In the Roman patronage system, food and table fellowship were sites of social signaling: who ate what with whom communicated status, alliance, and identity. The fact that different members of the Roman church community ate differently — some eating meat, some abstaining — would have created real social tension in the shared meal contexts.</p>',
    "4": '<p>The master-servant analogy in v4 ("who are you to judge someone else\'s servant?") draws on Roman household law. A slave\'s conduct was judged by their <em>dominus</em> (master), not by another household\'s members or by bystanders. For one household to evaluate another\'s servant was a social impropriety; Paul extends this logic to the divine household: the "strong" and "weak" are both servants of the same Lord, and the Lord alone has the right to judge whether they are "standing" or "falling" in their dietary practice.</p>',
    "5": '<p>The calendar observance dispute ("one person considers one day more sacred than another; another considers every day alike") likely refers to Jewish festival observances — Sabbath, the annual feasts, the Day of Atonement — rather than to arbitrary personal preferences about days. The early church\'s shift from Saturday Sabbath to Sunday worship (the Lord\'s Day, the first day of the week: 1 Cor 16:2; Acts 20:7; Rev 1:10) was already in process; Jewish Christians who maintained Sabbath observance alongside the Lord\'s Day celebration were not simply wrong but were honoring the continuing significance of the weekly Sabbath in their own practice.</p>',
    "6": '<p>"The one who regards the day, regards it for the Lord; and the one who eats, eats for the Lord, since they give thanks to God; while the one who abstains, abstains for the Lord and gives thanks to God." The criterion of "for the Lord" (<em>tō kyriō</em>) is the operative standard in vv6-9, applied three times. Both the Sabbath-keeper and the every-day-is-the-same person can honor the Lord in their practice; both the meat-eater and the vegetarian can honor the Lord in theirs. The theological root of the practice, not the practice itself, is what matters.</p>',
    "7": '<p>The principle "none of us lives to himself alone" (<em>oudeis gar hēmōn heautō zē</em>) challenges the fundamental assumption of Roman individualism. The Roman ideal of the autonomous free man who was master of his own estate and dependent on no one was a cultural aspiration that shaped Roman social ethics. Paul\'s claim that every person lives and dies "to the Lord" radically relocates the center of gravity from individual autonomy to Lordship — a comprehensive claim that no area of life falls outside the Lord\'s jurisdiction.</p>',
    "8": '<p>The Lordship of Christ over both life and death reflects the earliest Christian confession and its cosmic implications. The Psalmic tradition of "YHWH is my shepherd" (Ps 23) and the prophetic tradition of God as the Lord of Sheol and Hades (Ps 139:8; Amos 9:2) are applied to Christ: if Jesus is Lord, his Lordship extends over the final enemy (1 Cor 15:25-26; Rev 1:17-18). The practical implication for the food-debate is that no meal eaten "to the Lord" is a trivial matter, but equally, no dietary choice is beyond his jurisdiction and grace.</p>',
    "9": '<p>The death and resurrection of Christ as the grounds of his universal Lordship echoes Phil 2:9-11 (God has highly exalted him and given him the name above every name) and Eph 1:20-23 (raised and seated above all powers). The "for this very purpose Christ died and returned to life" (<em>eis touto gar Christos apethanen kai ezēsen</em>) connects the universal Lordship claim to the historical events that established it: the cross and resurrection are not merely personal redemption-events but cosmic-sovereignty events.</p>',
    "10": '<p>The "judgment seat of God" (<em>bēma tou theou</em>) — with some manuscripts reading "judgment seat of Christ" (<em>bēma tou Christou</em>, as in 2 Cor 5:10) — is a specific architectural term: the <em>bēma</em> was the raised platform from which the Roman magistrate pronounced legal judgments (see Acts 18:12-17 where Paul stands before Gallio\'s bēma in Corinth). Every Roman city had a bēma; the image would have been immediately recognizable to Paul\'s Roman readers. The point is that the human brothers and sisters who are judging each other about dietary practices will all stand before a bēma that renders their mutual judgments irrelevant.</p>',
    "11": '<p>The citation of Isaiah 45:23 — "every knee will bow to me, and every tongue will confess to God" — originally referred to YHWH\'s universal sovereignty acclaimed by all nations. Paul applied the same text to Christ in Philippians 2:10-11 ("at the name of Jesus every knee shall bow"). Here he applies it to the eschatological divine judgment in which every person, regardless of their position in the food-dispute, will give account. The Isaiah citation frames the entire creation as subject to divine judgment, making human judgments about each other\'s food practices both secondary and presumptuous.</p>',
    "12": '<p>The principle that "each of us will give account of ourselves to God" (<em>hekastos hēmōn peri heautou logon dōsei tō theō</em>) reflects the Jewish tradition of the heavenly books and the eschatological accounting (Dan 7:10; 1 Enoch 47:3; Rev 20:12). In that accounting, the question will not be "did you eat meat or abstain?" but whether one lived faithfully as the Lord\'s servant. The eschatological perspective de-centers the current disputes about food and calendar by placing them within the larger framework of the final divine accounting.</p>',
    "13": '<p>The wordplay on "judge" (<em>krinō</em>) in v13 shifts its object: instead of judging one another (<em>mēketi oun allēlous krinōmen</em> — let us no longer judge one another), the community should judge how not to put a stumbling block (<em>proskomma</em>) or obstacle (<em>skandalon</em>) before a brother or sister. The stumbling-block language echoes the stone-of-stumbling of 9:33 and 11:9, but here the stumbling is caused by community behavior rather than by unbelief in Christ. The one who places the stumbling block by insisting on rights that wound another\'s conscience becomes the cause of what they claimed to be preventing: harm to a fellow believer.</p>',
    "14": '<p>Paul\'s statement "I am convinced, being fully persuaded in the Lord Jesus, that nothing is unclean in itself" (<em>oida kai pepeismai en kyriō Iēsou hoti ouden koinon di\' heautou</em>) reflects the Markan tradition in which Jesus "declared all foods clean" (Mark 7:19). The Acts 10 vision (the unclean animals let down from heaven) and the Jerusalem Council\'s decision (Acts 15) had established that the food-purity distinctions of Levitical law did not apply to Gentile believers. Paul stands within this authoritative tradition. The qualification "but if anyone regards something as unclean, then for that person it is unclean" maintains the importance of conscience as the operative standard for individual practice.</p>',
    "15": '<p>The principle that the "strong" should not exercise their freedom in ways that harm the conscience of the "weak" is grounded theologically in Christ\'s death: "Do not destroy with your food someone for whom Christ died." The parallel passage in 1 Corinthians 8:11-12 makes the same argument: causing a weak believer to violate their conscience is "sinning against Christ." The rhetorical weight of "for whom Christ died" (<em>hyper hou Christos apethanen</em>) is enormous: the person whose conscience might be wounded is someone of infinite value — the object of the Messiah\'s atoning death.</p>',
    "16": '<p>"Do not let what you consider good be spoken of as evil" (<em>mē blasphēmeisthō oun hymōn to agathon</em>) addresses the public reputation of the community. If Gentile Christians\' exercise of their dietary freedom causes conflict in the church, outsiders will speak ill of the community\'s "good" — the gospel-shaped freedom that Christ has given. The missionary concern (that the community\'s internal disputes damage the gospel\'s credibility) is a recurring theme in Paul (1 Cor 10:32; Col 4:5-6; 1 Thess 4:12).</p>',
    "17": '<p>"The kingdom of God is not food and drink, but righteousness and peace and joy in the Holy Spirit" — the positive description of the kingdom\'s content redirects attention from the secondary issue (what one eats and drinks) to the primary reality: the divine reign is characterized by covenant-right-standing (<em>dikaiosynē</em>), restored relationship (<em>eirēnē</em>), and the Spirit\'s presence (<em>chara en pneumati hagiō</em>). These three — the same triad as 5:1-5 — are the substantive marks of the kingdom\'s presence, not dietary practices.</p>',
    "18": '<p>The one who "serves Christ in this way" — by prioritizing righteousness, peace, and joy over food-rights — "is acceptable to God and approved by people" (<em>euarestos tō theō kai dokimos tois anthrōpois</em>). The twin approval — divine and human — reflects Paul\'s understanding that genuine Christian ethics is not merely internally satisfying but externally credible. The word <em>dokimos</em> (tested and approved, as metal that has passed the assay) is the same standard Paul uses for his own ministry (2 Cor 10:18; 13:7) and for community life (1 Cor 11:19).</p>',
    "19": '<p>"Let us pursue what makes for peace and for mutual edification" (<em>diōkōmen ta tēs eirēnēs kai ta tēs oikodomēs tēs eis allēlous</em>) — the building-construction metaphor (<em>oikodomē</em> = building up) is common in Paul for community formation (1 Cor 14:4-5, 12, 17; Eph 4:12, 16). The Roman church as a building under construction needed both the foundation (the gospel) and the ongoing construction process (mutual edification). The peace that is to be pursued is not the absence of conflict alone but the positive shalom that characterizes the messianic community.</p>',
    "20": '<p>"Do not tear down the work of God for the sake of food" (<em>mē heneken brōmatos katalue to ergon tou theou</em>) — the construction/demolition metaphor: the community is God\'s building project (<em>to ergon tou theou</em>), and exercising food-rights in ways that destroy a brother\'s faith tears down what God is building. "Everything is indeed clean" (<em>panta men kathara</em>) affirms the theological principle; "but it is wrong for anyone to make another stumble by what they eat" (<em>alla kakon tō anthrōpō tō dia proskommatos esthionti</em>) applies the pastoral constraint. Right theology must be exercised in love.</p>',
    "21": '<p>"It is good not to eat meat or drink wine or do anything that causes your brother or sister to stumble" (<em>kalon to mē phagein krea mēde piein oinon mēde en hō ho adelphos sou proskoptei</em>) — the mention of wine (<em>oinon</em>) alongside meat suggests that the Roman community\'s disputes extended to wine as well. Jewish practice of avoiding wine in certain ritual contexts (Nazirite vow, Num 6:3; mourning periods; uncertainty about the kashrut of Gentile wine, which might have been used in pagan libations) would explain the abstention. The principle is the same: the limit on strong/Gentile freedom is not law but love for the weaker brother or sister.</p>',
    "22": '<p>"The faith that you have, keep between yourself and God" (<em>sy pistin echeis kata seauton eche enōpion tou theou</em>) — the "faith" here is specifically the conviction about food-freedom, not faith in Christ generally. Paul instructs the strong to maintain their theological conviction privately before God rather than parading it in ways that wound others. "Blessed is the one who does not condemn himself by what he approves" (<em>makarios ho mē krinōn heauton en hō dokimazei</em>) — the beatitude for the conscience-clear person: they can act consistently with their convictions without internal conflict.</p>',
    "23": '<p>"But whoever has doubts is condemned if they eat, because the eating is not from faith" (<em>ho de diakrinomenos ean phagē katakrinetai, hoti ouk ek pisteōs</em>). The one who eats despite doubting conscience condemns themselves — not by the act of eating but by the disconnection between action and conscience. The principle "everything that does not come from faith is sin" (<em>pan de ho ouk ek pisteōs hamartia estin</em>) is Paul\'s broadest ethical formulation: the criterion for sin is not merely external compliance with rules but the faith-orientation of the action. An action that violates conscience is sinful even if externally acceptable, because conscience is the internal expression of the faith-relationship with God.</p>'
  }
}

def main():
    existing = load_comm('mkt-context', 'romans')
    merge_comm(existing, ROMANS)
    save_comm('mkt-context', 'romans', existing)
    print('Romans 11–14 mkt-context written.')

if __name__ == '__main__':
    main()
